# Actualizar imágenes
updated = 0
for p in data["catalog"]:
    if p["id"] in url_map:
        new_img = url_map[p["id"]]
        if new_img.startswith("http") and p["img"] != new_img:
            p["img"] = new_img
            updated += 1

# Guardar data.json
with open("data.json", "w") as f:
    json.dump(data, f, ensure_ascii=False, indent=2)

print(f"✅ {updated} imágenes actualizadas en data.json")

# Generar catálogo para app.py
with open("catalog_output.txt", "w") as out:
    for p in data["catalog"]:
        img = p["img"].replace('"', '\\"')
